import React from 'react';
import  './App.scss';
import {BrowserRouter as Router,Routes,Route} from 'react-router-dom'
import Header from './componets/layout/Header';
import Home from './componets/HomePage/Home';
import Movie from './componets/MovieItems/Movie';
import Search from './componets/SearchItem/Search';
import Footer from './componets/layout/Footer';
import Popular from './componets/MovieCategory/Popular';
import TopRated from './componets/MovieCategory/TopRated';
import Upcoming from './componets/MovieCategory/Upcoming';
import Genres from './componets/MovieCategory/Genres';

const App=()=>{
    return(
     <div className='app'>
         <Router>
            <Header/>
            <Routes>
                <Route path={'/'} element={<Home/>}/>
                <Route path={'/movie/:id'} element={<Movie/>}/>
                <Route path={'/search/:searchTerm'} element={<Search/>}/>
                <Route path={'/popular'} element={<Popular/>}/>
                <Route path={'/toprated'} element={<TopRated/>}/>
                <Route path={'/upcoming'} element={<Upcoming/>}/>
                <Route path={'/genres'} element={<Genres/>}/>
            </Routes>
            <Footer/>
         </Router>
     </div>
    );
}

export default App;
